const items = $input.all().map(i => i.json);
const users = items.length === 1 && Array.isArray(items[0]) ? items[0] : items;
const userMap = {};
for (const u of users) {
  if (u && u.close_user_id) userMap[u.close_user_id] = u.id;
}
return [{ json: { userMap } }];

const userMap = $('Build User Map').first().json.userMap;
const typeItems = $input.all().map(i => i.json);
const types = typeItems.length === 1 && Array.isArray(typeItems[0]) ? typeItems[0] : typeItems;
const typeMap = {};
for (const t of types) {
  if (t && t.close_type_id) typeMap[t.close_type_id] = t.id;
}
return [{ json: { userMap, typeMap } }];

const triggerData = $('Start').first().json;
const since = triggerData.since || new Date().toISOString();
const until = triggerData.until || new Date().toISOString();
const currentDate = since.split('T')[0];
const endDate = until.split('T')[0];
return [{ json: { cursor: '', totalSynced: 0, currentDate, endDate, pageCount: 0 } }];

const data = $input.first().json;
const queries = [
  { type: 'object_type', object_type: 'activity.custom_activity' },
  {
    type: 'field_condition',
    field: { type: 'regular_field', object_type: 'activity.custom_activity', field_name: 'date_updated' },
    condition: {
      type: 'moment_range',
      on_or_after: { type: 'fixed_local_date', value: data.currentDate, which: 'start' },
      before: { type: 'fixed_local_date', value: data.currentDate, which: 'end' }
    }
  }
];

const body = {
  query: { type: 'and', queries },
  sort: [{ direction: 'asc', field: { object_type: 'activity.custom_activity', type: 'regular_field', field_name: 'date_updated' } }],
  _fields: { 'activity.custom_activity': ['id', 'lead_id', 'user_id', 'created_by', 'custom_activity_type_id', 'date_created', 'date_updated', 'custom'] },
  _limit: 200
};
if (data.cursor) body.cursor = data.cursor;
return [{ json: { requestBody: JSON.stringify(body) } }];

const response = $input.first().json;
const activities = response.data || [];
const lookups = $('Build Lookups').first().json;

if (activities.length === 0) {
  return [{ json: { _empty: true } }];
}

const stdFields = new Set(['id','lead_id','user_id','created_by','custom_activity_type_id','date_created','date_updated','organization_id','_type','lead_name','user_name','created_by_name','__object_type']);

return activities.map(act => {
  const cf = {};
  for (const [k, v] of Object.entries(act)) {
    if (!stdFields.has(k)) cf[k] = v;
  }
  return {
    json: {
      close_activity_id: act.id,
      type_id: lookups.typeMap[act.custom_activity_type_id] || null,
      user_id: lookups.userMap[act.user_id] || null,
      close_lead_id: act.lead_id || null,
      custom_fields: Object.keys(cf).length > 0 ? cf : null,
      close_created_at: act.date_created || null,
      synced_at: new Date().toISOString()
    }
  };
});

const all = $input.all().map(i => i.json).filter(i => !i._empty);
const nullUserIds = all.filter(r => r.user_id === null).length;
const nullTypeIds = all.filter(r => r.type_id === null).length;
return [{ json: { batch: all, count: all.length, nullUserIds, nullTypeIds } }];

const response = $('Search Close Activities').first().json;
const items = response.data || [];
const cursor = response.cursor || null;

const prev = $('Check More Pages').isExecuted
  ? $('Check More Pages').first().json
  : $('Init Pagination').first().json;

const batchCount = $('Aggregate Batch').first().json.count;
const cursorValid = cursor !== null && cursor !== undefined && cursor !== '';

if (cursorValid && items.length > 0) {
  return [{ json: {
    currentDate: prev.currentDate,
    endDate: prev.endDate,
    cursor: cursor,
    totalSynced: prev.totalSynced + batchCount,
    pageCount: (prev.pageCount || 0) + 1,
    hasMore: true
  } }];
}

const next = new Date(prev.currentDate + 'T00:00:00Z');
next.setUTCDate(next.getUTCDate() + 1);
const nextDate = next.toISOString().split('T')[0];
const hasMore = nextDate <= prev.endDate;

return [{ json: {
  currentDate: nextDate,
  endDate: prev.endDate,
  cursor: '',
  totalSynced: prev.totalSynced + batchCount,
  pageCount: 0,
  hasMore
} }];

const check = $('Check More Pages').last().json;
const totalSynced = check.totalSynced;
const syncRunId = $('Sync Start').first().json.id;
const nullUsers = check.totalNullUserIds || 0;
const nullTypes = check.totalNullTypeIds || 0;
let warning = '';
if (nullUsers > 0 || nullTypes > 0) {
  warning = 'FK Warning: ' + nullUsers + ' null user_ids, ' + nullTypes + ' null type_ids (of ' + totalSynced + ' total)';
}
return [{ json: { count: totalSynced, syncRunId, warning } }];
